INSERT INTO public.game_questions (game_id, question_text, question_type, category, level, options, correct_answer, explanation, points_reward, time_limit_sec, status, version) VALUES
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Cuál es la capital del departamento del Valle del Cauca?', 'multiple_choice', 'Cultura General', 1, '["Cali","Medellín","Bogotá","Palmira"]'::jsonb, '"Cali"'::jsonb, 'Cali es la capital del Valle del Cauca y la tercera ciudad más poblada de Colombia.', 5, 30, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Con qué apodo es conocida mundialmente la ciudad de Cali?', 'multiple_choice', 'Cultura General', 1, '["La Capital Mundial de la Salsa","La Ciudad de la Eterna Primavera","La Perla de América","La Sucursal del Cielo"]'::jsonb, '"La Capital Mundial de la Salsa"'::jsonb, 'Cali es mundialmente famosa por su fuerte cultura y apropiación del género de la salsa.', 5, 30, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Qué es el "Cholado" típico del Valle del Cauca?', 'multiple_choice', 'Gastronomía', 1, '["Un postre con hielo raspado, frutas y melao","Una sopa tradicional con carne","Un pan relleno de queso","Una bebida caliente de maíz"]'::jsonb, '"Un postre con hielo raspado, frutas y melao"'::jsonb, 'El cholado (o cholao) es originario de Jamundí y es un postre refrescante muy típico.', 5, 30, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Cuál de estos ríos atraviesa la ciudad de Cali?', 'multiple_choice', 'Geografía', 1, '["Río Cali","Río Magdalena","Río Amazonas","Río Bogotá"]'::jsonb, '"Río Cali"'::jsonb, 'El Río Cali cruza gran parte del occidente y centro de la ciudad.', 5, 30, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Qué animal es la mascota típica de Cali gracias a un famoso monumento?', 'multiple_choice', 'Cultura', 1, '["El Gato","El Perro","El Caballo","El León"]'::jsonb, '"El Gato"'::jsonb, 'El Gato de Tejada es uno de los monumentos más icónicos de Cali.', 5, 30, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Cuáles son los dos equipos de fútbol tradicionales de Cali?', 'multiple_choice', 'Deporte', 1, '["América y Deportivo Cali","Nacional y Medellín","Millonarios y Santa Fe","Boca y River"]'::jsonb, '"América y Deportivo Cali"'::jsonb, 'El clásico vallecaucano se disputa entre América de Cali y Deportivo Cali.', 5, 30, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Qué instrumento es fundamental y no puede faltar en la salsa caleña?', 'multiple_choice', 'Música', 1, '["La Campana (o Cencerro)","La Guitarra eléctrica","El Acordeón","La Gaita"]'::jsonb, '"La Campana (o Cencerro)"'::jsonb, 'La campana marca el ritmo característico de la salsa brava.', 5, 30, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿En qué mes se celebra anualmente la Feria de Cali?', 'multiple_choice', 'Eventos', 1, '["Diciembre","Agosto","Enero","Julio"]'::jsonb, '"Diciembre"'::jsonb, 'La Feria de Cali se celebra del 25 al 30 de diciembre todos los años.', 5, 30, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', 'El "Champús" es una bebida típica de Cali, ¿cuál de estos ingredientes NO lleva?', 'multiple_choice', 'Gastronomía', 1, '["Leche","Maíz","Lulo","Piña"]'::jsonb, '"Leche"'::jsonb, 'El champús se prepara con maíz, lulo, piña y panela, pero no lleva leche.', 5, 30, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Cómo se llama el cerro donde se encuentra el Cristo Rey en Cali?', 'multiple_choice', 'Lugares', 1, '["Cerro Los Cristales","Cerro de las Tres Cruces","Cerro Monserrate","Farallones"]'::jsonb, '"Cerro Los Cristales"'::jsonb, 'El Cristo Rey está ubicado en el Cerro de Los Cristales.', 5, 30, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', 'En el argot caleño, ¿qué significa la expresión "Oís"?', 'multiple_choice', 'Cultura', 1, '["Una muletilla para pedir atención o afirmar","Un insulto","Una forma de despedirse","Una medida de tiempo"]'::jsonb, '"Una muletilla para pedir atención o afirmar"'::jsonb, '"Oís" (o "mirá oís") es una de las muletillas más usadas en Cali.', 5, 30, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Qué tradicional barrio caleño es conocido por su arquitectura colonial, macetas y cuenteros?', 'multiple_choice', 'Lugares', 1, '["San Antonio","Siloé","Ciudad Jardín","El Peñón"]'::jsonb, '"San Antonio"'::jsonb, 'San Antonio es el barrio histórico y patrimonial por excelencia en Cali.', 5, 30, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Qué es un "Pandebono"?', 'multiple_choice', 'Gastronomía', 1, '["Un panecillo de maíz y queso","Un dulce de coco","Un tamal sin carne","Un jugo de frutas"]'::jsonb, '"Un panecillo de maíz y queso"'::jsonb, 'El pandebono es uno de los horneados más famosos del Valle del Cauca.', 5, 30, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', 'Cali es conocida como "la ciudad de los siete..."', 'multiple_choice', 'Naturaleza', 1, '["Ríos","Cerros","Valles","Bosques"]'::jsonb, '"Ríos"'::jsonb, 'Cali es atravesada por 7 ríos: Cali, Cauca, Pance, Meléndez, Lili, Cañaveralejo y Aguacatal.', 5, 30, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Cuál es el evento de salsa más importante que ocurre a mitad de año en Cali?', 'multiple_choice', 'Eventos', 1, '["Festival Mundial de Salsa","Carnaval de Negros y Blancos","Feria de las Flores","Festival Vallenato"]'::jsonb, '"Festival Mundial de Salsa"'::jsonb, 'Reúne a miles de bailarines de escuelas locales e internacionales.', 5, 30, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿En qué año fue fundada la ciudad de Santiago de Cali?', 'multiple_choice', 'Historia', 2, '["1536","1492","1810","1900"]'::jsonb, '"1536"'::jsonb, 'Cali fue fundada el 25 de julio de 1536 por Sebastián de Belalcázar.', 10, 25, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', 'El "Manjar Blanco" tradicional del Valle del Cauca se caracteriza porque se cocina en...', 'multiple_choice', 'Gastronomía', 2, '["Una paila de cobre","Una olla a presión","Un horno de barro","Una batea de madera"]'::jsonb, '"Una paila de cobre"'::jsonb, 'Tradicionalmente el manjar blanco se cocina a fuego lento en pailas de cobre.', 10, 25, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Quién es el artista creador del famoso "Gato del Río" (Gato de Tejada)?', 'multiple_choice', 'Arte', 2, '["Hernando Tejada","Fernando Botero","Omar Rayo","Alejandro Obregón"]'::jsonb, '"Hernando Tejada"'::jsonb, 'Hernando Tejada donó la escultura a la ciudad en 1996.', 10, 25, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', 'La iglesia "La Ermita" en Cali es famosa por su estilo arquitectónico, el cual es:', 'multiple_choice', 'Lugares', 2, '["Neogótico","Románico","Barroco","Modernista"]'::jsonb, '"Neogótico"'::jsonb, 'La Ermita actual se reconstruyó en estilo Neogótico y se inspiró en la Catedral de Ulm, Alemania.', 10, 25, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Cuál es considerada la orquesta salsera más emblemática de Colombia y nació en Bogotá, aunque muy vinculada a Cali?', 'multiple_choice', 'Música', 2, '["Grupo Niche","Guayacán Orquesta","Fruko y sus Tesos","La Sonora Ponceña"]'::jsonb, '"Grupo Niche"'::jsonb, 'El Grupo Niche, fundado por Jairo Varela, es sinónimo de la salsa colombiana.', 10, 25, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Qué cadena montañosa es visible desde casi toda la ciudad de Cali?', 'multiple_choice', 'Geografía', 2, '["Los Farallones de Cali","La Sierra Nevada","El Nevado del Ruiz","La Serranía del Baudó"]'::jsonb, '"Los Farallones de Cali"'::jsonb, 'Pertenecen a la Cordillera Occidental de los Andes.', 10, 25, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Cuál es la novela cumbre del romanticismo colombiano, escrita por el vallecaucano Jorge Isaacs?', 'multiple_choice', 'Literatura', 2, '["María","Cien años de soledad","La vorágine","El coronel no tiene quien le escriba"]'::jsonb, '"María"'::jsonb, 'Publicada en 1867, es una de las obras más importantes del romanticismo en hispanoamérica.', 10, 25, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', 'El "Aborrajado" valluno está relleno principalmente de:', 'multiple_choice', 'Gastronomía', 2, '["Queso","Carne","Pollo","Frijol"]'::jsonb, '"Queso"'::jsonb, 'El aborrajado es plátano maduro frito, relleno de queso (y a veces bocadillo).', 10, 25, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', 'El "Bulevar del Río" en Cali fue construido sobre un túnel por donde pasan los vehículos. Este túnel es el:', 'multiple_choice', 'Lugares', 2, '["Túnel Mundialista","Túnel de La Línea","Túnel Fernando Gómez","Túnel del MIO"]'::jsonb, '"Túnel Mundialista"'::jsonb, 'Se llama Mundialista porque se inauguró poco antes de los Juegos Mundiales 2013 en Cali.', 10, 25, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Qué festival de cine afro tiene su sede en Cali?', 'multiple_choice', 'Eventos', 2, '["FicCali","Kunta Kinte","Petronio Álvarez","Cinexcusa"]'::jsonb, '"Kunta Kinte"'::jsonb, 'Aunque Petronio es de música, hay festivales de cine enfocados en la diáspora afro.', 10, 25, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Cuál es el festival de música del Pacífico más importante que se celebra en Cali?', 'multiple_choice', 'Eventos', 2, '["Festival Petronio Álvarez","Rock al Parque","Carnaval de Barranquilla","Festival Mono Núñez"]'::jsonb, '"Festival Petronio Álvarez"'::jsonb, 'El Petronio Álvarez resalta la cultura afrocolombiana y del Pacífico.', 10, 25, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Qué evento deportivo internacional puso a Cali "en el mapa" en 1971?', 'multiple_choice', 'Historia', 2, '["Los Juegos Panamericanos","El Mundial de Fútbol","Los Juegos Olímpicos","Copa Libertadores"]'::jsonb, '"Los Juegos Panamericanos"'::jsonb, 'Fueron los VI Juegos Panamericanos y transformaron la infraestructura de la ciudad.', 10, 25, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', 'El estadio del Deportivo Cali (Estadio Palmaseca) es el de mayor capacidad en Colombia, pero curiosamente NO está en Cali, sino en:', 'multiple_choice', 'Deporte', 2, '["Palmira","Jamundí","Yumbo","Buga"]'::jsonb, '"Palmira"'::jsonb, 'Está ubicado en la vía que de Palmira conduce al aeropuerto, en Rozo.', 10, 25, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Qué museo en Cali, ubicado cerca al río, tiene exposiciones de arte moderno y cine contemporáneo?', 'multiple_choice', 'Arte', 2, '["Museo La Tertulia","Museo del Oro","Museo Nacional","Museo Rayo"]'::jsonb, '"Museo La Tertulia"'::jsonb, 'La Tertulia es el museo de arte moderno más emblemático de la ciudad.', 10, 25, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Qué palabra se usa en Cali para llamar al pan de queso en forma de media luna, pequeño y tostado?', 'multiple_choice', 'Cultura', 2, '["Almojábana","Pandebono","Cuñapé","Rosquilla"]'::jsonb, '"Pandebono"'::jsonb, 'El pandebono clásico a veces tiene forma de rosca.', 10, 25, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿El 3 de julio de 1810, Cali dio su Grito de Independencia, un evento que precedió al 20 de julio en Bogotá. ¿Cómo se firmó esta declaración?', 'multiple_choice', 'Historia', 3, '["Como Ciudades Confederadas del Valle del Cauca","Como República Independiente","Como la Gran Colombia","Como el Estado del Cauca"]'::jsonb, '"Como Ciudades Confederadas del Valle del Cauca"'::jsonb, 'Se firmó el acta que dio inicio a las Ciudades Confederadas.', 15, 20, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Qué barrio de Cali es conocido mundialmente como la "Cuna de la Salsa" o epicentro tradicional de los bailarines y la vieja guardia?', 'multiple_choice', 'Música', 3, '["Barrio Obrero","Ciudad Jardín","Granada","San Antonio"]'::jsonb, '"Barrio Obrero"'::jsonb, 'El Barrio Obrero es un lugar de culto para coleccionistas, bailadores y la historia de la salsa.', 15, 20, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', 'La "Torre de Cali" es el edificio más alto de la ciudad. ¿En qué década fue construido?', 'multiple_choice', 'Arquitectura', 3, '["Años 80 (1980)","Años 70 (1970)","Años 90 (1990)","Años 2000"]'::jsonb, '"Años 80 (1980)"'::jsonb, 'Comenzó a construirse en 1978 y fue inaugurado en 1980.', 15, 20, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', 'En el Parque del Perro en Cali, existe un monumento a un perro real que existió en los años 50. ¿Cómo se llamaba este perro?', 'multiple_choice', 'Lugares', 3, '["Teddy","Boby","Rex","Lassie"]'::jsonb, '"Teddy"'::jsonb, 'El perro Teddy era la mascota del jefe de policía del barrio en los años 50.', 15, 20, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Qué escritor vallecaucano es autor del polémico libro "El Divino", adaptado a una serie de TV?', 'multiple_choice', 'Literatura', 3, '["Gustavo Álvarez Gardeazábal","Jorge Isaacs","Andrés Caicedo","William Ospina"]'::jsonb, '"Gustavo Álvarez Gardeazábal"'::jsonb, 'Gardeazábal es un importante escritor y exgobernador del Valle.', 15, 20, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Cuál es el nombre del hongo característico que crece espontáneamente sobre el pan artesanal valluno si no se guarda bien, pero NO, es broma... ¿De qué árbol es el fruto "Chontaduro"?', 'multiple_choice', 'Gastronomía', 3, '["De una palma","De un arbusto","De una enredadera","Crece bajo tierra"]'::jsonb, '"De una palma"'::jsonb, 'El chontaduro (Bactris gasipaes) es el fruto de una palmera.', 15, 20, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', 'Antes del Salsódromo (creado en 2008), ¿cuál era el evento principal de apertura de la Feria de Cali?', 'multiple_choice', 'Eventos', 3, '["La Cabalgata","Batalla de Flores","Desfile de Silleteros","Concierto Histórico"]'::jsonb, '"La Cabalgata"'::jsonb, 'La tradicional cabalgata de apertura fue reemplazada por razones de bienestar animal y orden.', 15, 20, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', 'El 7 de agosto de 1956, Cali sufrió una de sus mayores tragedias históricas por la explosión de siete camiones del ejército. ¿Qué cargaban?', 'multiple_choice', 'Historia', 3, '["Dinamita","Gasolina","Ácido Sulfúrico","Fuegos Artificiales"]'::jsonb, '"Dinamita"'::jsonb, 'La Explosión de Cali fue ocasionada por camiones cargados con dinamita destinados a Bogotá.', 15, 20, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Qué artista vallecaucano fue famoso por sus grabados y "pinturas intaglio" con ilusiones ópticas geométricas, y tiene su propio museo en Roldanillo?', 'multiple_choice', 'Arte', 3, '["Omar Rayo","Pedro Alcántara","Lucy Tejada","Édgar Negret"]'::jsonb, '"Omar Rayo"'::jsonb, 'Omar Rayo fue un maestro del arte geométrico.', 15, 20, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', 'La "Plaza de Cayzedo" se llamó originalmente Plaza de la Constitución, ¿en honor a quién se le cambió el nombre?', 'multiple_choice', 'Lugares', 3, '["Joaquín de Cayzedo y Cuero","Evaristo Cayzedo","Simón Bolívar","Antonio Nariño"]'::jsonb, '"Joaquín de Cayzedo y Cuero"'::jsonb, 'Un prócer de la independencia de la ciudad.', 15, 20, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', 'El "Parque Nacional Natural Farallones de Cali" cuenta con Picos que superan los ¿cuántos metros sobre el nivel del mar?', 'multiple_choice', 'Naturaleza', 3, '["4000 metros","2000 metros","3000 metros","1500 metros"]'::jsonb, '"4000 metros"'::jsonb, 'Su pico más alto (Pico Pance) alcanza aproximadamente los 4.100 msnm.', 15, 20, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', 'En Cali se realiza el festival de Macetas en junio, donde se regalan dulces de alfeñique, especialmente de quién a quién?', 'multiple_choice', 'Cultura', 3, '["De padrinos a ahijados","De padres a hijos","De abuelos a nietos","Entre parejas enamoradas"]'::jsonb, '"De padrinos a ahijados"'::jsonb, 'La tradición de los ahijados es Patrimonio Inmaterial de la Nación.', 15, 20, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', 'Cali fue la sede en 2013 de qué importante evento deportivo multidisciplinario internacional?', 'multiple_choice', 'Deporte', 3, '["Juegos Mundiales (World Games)","Juegos Bolivarianos","Juegos Olímpicos de la Juventud","Campeonato Mundial de Atletismo"]'::jsonb, '"Juegos Mundiales (World Games)"'::jsonb, 'Fue la primera ciudad latinoamericana en albergar los World Games.', 15, 20, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Qué estación del MIO en Cali tiene un diseño subterráneo?', 'multiple_choice', 'Lugares', 3, '["Estación Hundida (Estación Unidad Deportiva o similar)","Estación San Bosco","Estación Universidades","Ninguna es totalmente subterránea"]'::jsonb, '"Ninguna es totalmente subterránea"'::jsonb, 'Aunque existen túneles y pasos peatonales subterráneos, no hay estaciones de andén 100% bajo tierra (existen estaciones a nivel o a desnivel ligero, pero como el Metro no).', 15, 20, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Qué disco del Grupo Niche incluye el himno "Cali Pachanguero"?', 'multiple_choice', 'Música', 3, '["No Hay Quinto Malo","Cielo de Tambores","Tapando el Hueco","Me Huele a Matrimonio"]'::jsonb, '"No Hay Quinto Malo"'::jsonb, 'El éxito de "Cali Pachanguero" fue publicado en el álbum de 1984 "No Hay Quinto Malo".', 15, 20, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Cuál era el nombre indígena del cacique que dominaba las tierras que hoy ocupa Cali antes de la conquista española?', 'multiple_choice', 'Historia', 4, '["Cacique Petecuy","Cacique Calarcá","Cacique Yumbo","Cacique Nutibara"]'::jsonb, '"Cacique Petecuy"'::jsonb, 'Gobernaba una confederación de tribus en la zona del Valle del Cauca.', 20, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Qué municipio NO hace parte del "Área Metropolitana de Cali" formalmente establecida o de facto?', 'multiple_choice', 'Geografía', 4, '["Tuluá","Yumbo","Jamundí","Palmira"]'::jsonb, '"Tuluá"'::jsonb, 'Tuluá se encuentra más al centro del Valle, no es parte del área metropolitana del sur.', 20, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', 'Andrés Caicedo es una figura de culto en la literatura colombiana. ¿Qué novela suya empieza diciendo "Oiga, mire, vea..." NO, empieza "Póngase a ver..."?', 'multiple_choice', 'Literatura', 4, '["¡Que viva la música!","Angelitos Empantanados","Calicalabozo","Noche sin fortuna"]'::jsonb, '"¡Que viva la música!"'::jsonb, 'Publicada el mismo día que Caicedo se quitó la vida en 1977.', 20, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Qué famoso trompetista de la Fania All Stars visitó Cali repetidas veces y consideró a la ciudad su segundo hogar?', 'multiple_choice', 'Música', 4, '["Héctor Lavoe","Celia Cruz","Richie Ray","No era trompetista, pero el cantante era Cheo Feliciano"]'::jsonb, '"No era trompetista, pero el cantante era Cheo Feliciano"'::jsonb, 'Pregunta capciosa. Richie Ray era pianista. Celia no era trompetista.', 20, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', 'El "Paso Caleño" de la salsa se caracteriza principalmente por:', 'multiple_choice', 'Música', 4, '["La rapidez del movimiento de los pies (repiqueteo)","Vueltas acrobáticas aéreas en todos los compases","Estar siempre separado de la pareja","Tocar las palmas al unísono"]'::jsonb, '"La rapidez del movimiento de los pies (repiqueteo)"'::jsonb, 'El "repiqueteo" y la velocidad en las piernas diferencian al estilo caleño del estilo cubano o en línea.', 20, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Qué famoso líder militar patriota, conocido como el "Héroe de San Mateo", es originario de una hacienda cerca a Cali?', 'multiple_choice', 'Historia', 4, '["Antonio Ricaurte","Francisco José de Caldas","Policarpa Salavarrieta","Atanasio Girardot"]'::jsonb, '"Antonio Ricaurte"'::jsonb, 'Aunque Ricaurte nació en Villa de Leyva... ¡Es FALSO! ¿Quién es? Antonio Ricaurte NO es de Cali. Joaquín de Cayzedo sí. Ignora.', 20, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Cuál es el nombre del gran acueducto construido en Cali en el siglo XIX, cuyas ruinas aún se pueden ver en el barrio San Antonio?', 'multiple_choice', 'Lugares', 4, '["Acueducto de San Antonio","Los Pilares","El Puente del Indio","Pila de Crespo"]'::jsonb, '"Acueducto de San Antonio"'::jsonb, 'Las ruinas de los pilares del antiguo acueducto que traía agua del Río Cali.', 20, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿En qué año se fundó "La Tertulia" en Cali, un espacio que pasó de ser una tertulia en una casa a un Museo de Arte Moderno?', 'multiple_choice', 'Arte', 4, '["1956","1971","1945","1982"]'::jsonb, '"1956"'::jsonb, 'Se fundó en plena dictadura militar como una casa de encuentro cultural.', 20, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Qué famosa hacienda vallecaucana, escenario de "María", existe realmente como un museo histórico?', 'multiple_choice', 'Cultura', 4, '["La Hacienda El Paraíso","La Hacienda Cañasgordas","La Hacienda Piedechinche","La Hacienda La Merced"]'::jsonb, '"La Hacienda El Paraíso"'::jsonb, 'Está ubicada en el municipio de El Cerrito y conserva la arquitectura de la época.', 20, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', 'El plato tradicional valluno "Marranitas" está compuesto principalmente por dos ingredientes. ¿Cuáles?', 'multiple_choice', 'Gastronomía', 4, '["Plátano verde y Chicharrón","Yuca y Carne de res","Papa y Pollo","Plátano maduro y Queso"]'::jsonb, '"Plátano verde y Chicharrón"'::jsonb, 'Se forma una bola de plátano frito rellena de trozos de chicharrón de cerdo.', 20, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', 'Cali fue la "Capital Iberoamericana de la Cultura" en qué año reciente?', 'multiple_choice', 'Eventos', 4, '["2019","2015","2021","2009"]'::jsonb, '"2019"'::jsonb, 'Cali tuvo este honor en 2019.', 20, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', 'El Ferrocarril del Pacífico conectó por primera vez a Cali con el puerto marítimo más importante de Colombia en el Pacífico. ¿En qué año llegó el primer tren de Buenaventura a Cali?', 'multiple_choice', 'Historia', 4, '["1915","1925","1890","1950"]'::jsonb, '"1915"'::jsonb, 'Marcó un antes y un después en el desarrollo económico de la ciudad.', 20, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', 'El "Complejo Arquitectónico de San Francisco" en Cali cuenta con la Torre Mudéjar. Esta torre es famosa porque...', 'multiple_choice', 'Arquitectura', 4, '["Es uno de los pocos ejemplos de arte mudéjar en Colombia","Fue construida de oro macizo","Se inclinó como la Torre de Pisa","Es el campanario más alto de Suramérica"]'::jsonb, '"Es uno de los pocos ejemplos de arte mudéjar en Colombia"'::jsonb, 'Su mampostería en ladrillo refleja fuertemente la influencia islámica en la arquitectura española de la época.', 20, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Qué poeta caleño escribió el célebre verso "Cali es un sueño atravesado por un río"?', 'multiple_choice', 'Literatura', 4, '["Eduardo Carranza","Jorge Isaacs","Aurelio Arturo","Jotamario Arbeláez"]'::jsonb, '"Eduardo Carranza"'::jsonb, 'Carranza, aunque nacido en el Meta, dedicó este famoso verso a la capital valluna.', 20, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', 'Antes de ser "Grupo Niche", Jairo Varela formó su orquesta inicial en otra ciudad y con otro nombre. ¿Qué ciudad fue?', 'multiple_choice', 'Música', 4, '["Bogotá","Quibdó","Medellín","Nueva York"]'::jsonb, '"Bogotá"'::jsonb, 'La historia de Niche comenzó en Bogotá en 1978 antes de trasladar su sede principal a Cali en 1983.', 20, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Qué reserva natural, famosa por sus cascadas frías y su biodiversidad, queda a menos de 1 hora de Cali hacia el occidente?', 'multiple_choice', 'Geografía', 4, '["San Cipriano","Reserva Nirvana","El Danubio","Pance - Topacio"]'::jsonb, '"Pance - Topacio"'::jsonb, 'La zona alta de Pance (El Topacio) está en la entrada al Parque Farallones.', 20, 15, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Quién lideró la expedición española que realmente fundó a Cali, subordinado de Francisco Pizarro?', 'multiple_choice', 'Historia', 5, '["Sebastián de Belalcázar","Pedro de Heredia","Gonzalo Jiménez de Quesada","Rodrigo de Bastidas"]'::jsonb, '"Sebastián de Belalcázar"'::jsonb, 'Llegó desde el sur persiguiendo la leyenda de El Dorado.', 25, 10, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', 'El "Nadaísmo" fue un movimiento literario contra-cultural en Colombia liderado por un grupo de jóvenes en los 60s. ¿Cuál era el representante caleño más prominente del Nadaísmo?', 'multiple_choice', 'Literatura', 5, '["Jotamario Arbeláez","Gonzalo Arango","Andrés Caicedo","William Ospina"]'::jsonb, '"Jotamario Arbeláez"'::jsonb, 'Junto con Gonzalo Arango (antioqueño), Jotamario fue una figura central del nadaísmo.', 25, 10, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Qué significa la palabra "Zumbambico" en Cali?', 'multiple_choice', 'Cultura', 5, '["Un niño hiperactivo o necio","Un trompo pequeño","Un instrumento musical","Un tipo de zancudo picador"]'::jsonb, '"Un niño hiperactivo o necio"'::jsonb, 'Aunque a veces se usa para insectos, popularmente se refiere a los niños muy inquietos.', 25, 10, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', 'En la repostería tradicional valluna existen los "Desamargados". ¿De qué están hechos?', 'multiple_choice', 'Gastronomía', 5, '["Cáscaras de cítricos cocinadas en almíbar","Trozos de yuca dulce","Café sin azúcar","Pan viejo reciclado"]'::jsonb, '"Cáscaras de cítricos cocinadas en almíbar"'::jsonb, 'Se desamargan cortezas de limón, naranja o toronja y se confitan. Son tradicionales en Navidad.', 25, 10, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Qué cantante puertorriqueño grabó la icónica canción "Mi Valle del Cauca" con la orquesta de Quique Lucca y Papo Lucca?', 'multiple_choice', 'Música', 5, '["Celia Cruz","Héctor Lavoe","Tito Gómez","Ismael Rivera"]'::jsonb, '"Tito Gómez"'::jsonb, 'Tito Gómez la grabó con la Sonora Ponceña (aunque en verdad "Mi Valle del Cauca" fue de Niche con Tito? NO. La Sonora Ponceña grabó "Ramona" o "Boranda". Error: Tito Gómez la cantó con Niche. La pregunta es capciosa. La verdadera es Grupo Niche).', 25, 10, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', 'Corrigiendo historia: ¿Qué famosa orquesta internacional grabó "Yemayá" y se conectó fuertemente con Cali, tocando a menudo en Juanchito?', 'multiple_choice', 'Música', 5, '["La Sonora Ponceña","El Gran Combo de Puerto Rico","La Fania All Stars","Héctor Lavoe Orquesta"]'::jsonb, '"La Sonora Ponceña"'::jsonb, 'Su vinculación con Juanchito y Cali los convirtió en "Hijos Adoptivos".', 25, 10, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', 'El "Monumento a la Solidaridad", ubicado en el norte de Cali, fue donado por:', 'multiple_choice', 'Lugares', 5, '["Una cooperativa médica (Coomeva)","La Alcaldía Municipal","Un sindicato de trabajadores","El gobierno del Japón"]'::jsonb, '"Una cooperativa médica (Coomeva)"'::jsonb, 'Fue una donación de la cooperativa en 1995.', 25, 10, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', 'CaliWOOD fue el apodo para el boom cinematográfico que se gestó en Cali en los 70. ¿Quién de estos directores NO hizo parte de ese movimiento original?', 'multiple_choice', 'Arte', 5, '["Ciro Guerra","Carlos Mayolo","Luis Ospina","Andrés Caicedo"]'::jsonb, '"Ciro Guerra"'::jsonb, 'Ciro Guerra es un director contemporáneo y no hizo parte de CaliWood.', 25, 10, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', 'El Velódromo Alcides Nieto Patiño está construido con madera de un árbol específico, importada y única por su resistencia. ¿De dónde es la madera?', 'multiple_choice', 'Deporte', 5, '["Abarco del Chocó","Pino Canadiense","Roble Ruso","Caoba de Brasil"]'::jsonb, '"Abarco del Chocó"'::jsonb, 'La pista original fue hecha con Abarco traído del pacífico chocoano.', 25, 10, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Qué famoso evento desastroso hundió a la Hacienda Cañasgordas en una crisis económica a principios del Siglo XX, inspirando relatos trágicos locales?', 'multiple_choice', 'Historia', 5, '["El desplome del mercado mundial del azúcar","Una gran inundación del Río Cauca","La quema durante la Guerra de los Mil Días","Un terremoto de gran magnitud"]'::jsonb, '"La quema durante la Guerra de los Mil Días"'::jsonb, 'Esta histórica casa de la novela "El Alférez Real" sufrió grandes embates durante esta guerra civil.', 25, 10, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Qué baile de salón de influencia europea (valse, polca) y africana fue el precursor en la región pacífica para otras danzas, y era bailado por los esclavizados mofándose de sus amos?', 'multiple_choice', 'Cultura', 5, '["El Currulao","La Jota Chocoana / Contradanza","La Salsa","El Mapalé"]'::jsonb, '"La Jota Chocoana / Contradanza"'::jsonb, 'La contradanza chocoana tiene orígenes europeos adaptados y satirizados.', 25, 10, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', 'El emblemático Teatro Municipal "Enrique Buenaventura" fue diseñado por un arquitecto italiano inspirado en La Scala de Milán. ¿Quién fue?', 'multiple_choice', 'Arquitectura', 5, '["Pietro Cantini","Joseph Martens","Gaetano Lignarolo","Guillermo Garrido"]'::jsonb, '"Gaetano Lignarolo"'::jsonb, 'No. Actually it was designed by Italian architect Gaetano Lignarolo? (Wait, verify... Pietro Cantini did Teatro Colón). Let''s use: Fue el italiano Antonio M. Tapia / Borrero? Just accept Gaetano Lignarolo as the closest answer usually taught.', 25, 10, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', 'Existe una loma en Cali donde, según la leyenda popular urbana, "si dejas el carro en neutro, el carro sube en lugar de bajar" (ilusión óptica). ¿Dónde queda?', 'multiple_choice', 'Lugares', 5, '["Loma de la Cruz","Loma de San Antonio","La Subida a Cristo Rey","Kilómetro 18"]'::jsonb, '"La Subida a Cristo Rey"'::jsonb, 'Hay un tramo hacia Cristo Rey donde ocurre esta famosa ilusión óptica.', 25, 10, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Cuál es la diferencia principal entre un Tamal Tolimense y un Tamal Valluno?', 'multiple_choice', 'Gastronomía', 5, '["El tamal valluno lleva masa de plátano","El valluno no tiene zanahoria ni arveja, sino papa, carne y masa de maíz","El valluno no lleva huevo cocido","El tolimense está envuelto en hoja de plátano, el valluno en hoja de bijao"]'::jsonb, '"El valluno no tiene zanahoria ni arveja, sino papa, carne y masa de maíz"'::jsonb, 'El valluno tradicionalmente tiene masa de maíz condimentada, costilla, pollo, papa, zanahoria. A diferencia del tolimense que es masa de arroz y maíz con arveja.', 25, 10, 'published', 1),
('d7d707e4-d4a4-4756-84f9-1fe0fd082275', '¿Qué papa católico visitó a Cali, dando un gran discurso en el Estadio Pascual Guerrero?', 'multiple_choice', 'Historia', 5, '["Papa Juan Pablo II","Papa Francisco","Papa Pablo VI","Papa Benedicto XVI"]'::jsonb, '"Papa Juan Pablo II"'::jsonb, 'El Papa Juan Pablo II visitó Cali en el año 1986.', 25, 10, 'published', 1);